package coralnpu

import chisel3._
import chisel3.util._
import common._
import _root_.circt.stage.{ChiselStage,FirtoolOption}
import chisel3.stage.ChiselGeneratorAnnotation
import scala.annotation.nowarn

object Mlu {
  def apply(p: Parameters): Mlu = {
    return Module(new Mlu(p))
  }
}

object MluOp extends ChiselEnum {
  val MUL = Value
  val MULH = Value
  val MULHSU = Value
  val MULHU = Value
  val Entries = Value
}

class MluCmd(p: Parameters) extends Bundle {
  val addr = UInt(log2Ceil(p.scalarRegCount).W)
  val op = MluOp()
}

class MluStage1(p: Parameters) extends Bundle {
  val rd = UInt(log2Ceil(p.scalarRegCount).W)
  val op = MluOp()
  val sel = UInt(p.instructionLanes.W)
}

class MluStage2(p: Parameters) extends Bundle {
  val rd = UInt(log2Ceil(p.scalarRegCount).W)
  val op = MluOp()
  val prod = SInt((2 * p.xlen + 2).W)
}

class Mlu(p: Parameters) extends Module {
  val io = IO(new Bundle {
    // Decode cycle.
    val req = Vec(p.instructionLanes, Flipped(Decoupled(new MluCmd(p))))

    // Execute cycle.
    val rs1 = Vec(p.instructionLanes, Flipped(new RegfileReadDataIO(p)))
    val rs2 = Vec(p.instructionLanes, Flipped(new RegfileReadDataIO(p)))
    val rd  = Decoupled(Flipped(new RegfileWriteDataIO(p)))
  })

  // Stage 1 select and decode instruction
  val arb = Module(new Arbiter(new MluCmd(p), p.instructionLanes))
  arb.io.in <> io.req

  val stage1 = Wire(Decoupled(new MluStage1(p)))
  stage1.valid := arb.io.out.valid
  stage1.bits.rd := arb.io.out.bits.addr
  stage1.bits.op := arb.io.out.bits.op
  stage1.bits.sel := UIntToOH(arb.io.chosen)
  arb.io.out.ready := stage1.ready

// Enable extra logic for verification purposes.
var enableVerification = false

// TODO: It might seem intuitive to couple exposeDebugPorts and
// enableVerification, as debug ports are only needed for verification.
// However, coupling them is not trivial because enableVerification also
// enables the full Retirement Buffer (ROB) tracking mode (mini = false).
// Under configurations with RVV disabled but Float enabled (like core_mini_axi_sim),
// the full ROB mode has hardware bugs/hangs (e.g. vector store waits and reset
// oscillations). We still need the debug ports exposed for these targets to
// generate instruction traces for riscv-dv co-simulation, but we must run
// the ROB in mini mode (enableVerification = false) to avoid the hangs.
// Thus, we keep these parameters decoupled.
// Expose the debug/trace ports at the module boundary.
var exposeDebugPorts = false

// Expose ports if explicitly requested, or automatically if full verification is enabled.
def shouldExposeDebugPorts: Boolean = { exposeDebugPorts || enableVerification }

// Enable RVV. This conforms to the RVV1.0 specification.
var enableRvv = false
val rvvVlen = 128
def rvvVlenb: Int = { rvvVlen / 8 }

def useRetirementBuffer: Boolean = { enableVerification }

// Scalar Floating point
